mapper.select:
SELECT bgwriter_agg_id as id, TO_CHAR(collected_at, 'HH24:MI') as timestamp, COALESCE(total_buffers_clean + total_buffers_backend, 0) as buffersAlloc, COALESCE(avg_clean_rate, 0.0) as cleanRate, -- Backend rate 계산 (backend buffers / 시간 간격, 초당) COALESCE(total_buffers_backend / 60.0, 0.0) as backendRate, 0 as checkpointBuffers, COALESCE(avg_backend_flush_ratio, 0.0) as backendRatio, -- Fsync rate 계산 (초당) COALESCE(total_backend_fsync / 60.0, 0.0) as fsyncRate, -- Maxwritten rate 계산 (분당) COALESCE(total_maxwritten_clean, 0) as maxWrittenRate, -- avg_cycle_time_ms 컬럼이 없으므로 0으로 처리 0.0 as avgCycleTime, COALESCE(status, '정상') as status FROM bgwriter_agg_1m WHERE instance_id = #{instanceId} AND collected_at >= #{startTime} AND collected_at <= #{endTime}
AND status IN
#{status}
ORDER BY collected_at DESC
